import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Gửi email và pass lên server kiểm tra
      const { data } = await axios.post('http://localhost:5000/api/users/login', { email, password });
      
      // QUAN TRỌNG: Lưu thông tin người dùng vào bộ nhớ trình duyệt (LocalStorage)
      // Để khi F5 lại trang thì web vẫn nhớ là đã đăng nhập rồi
      localStorage.setItem('userInfo', JSON.stringify(data));
      
      alert('Đăng nhập thành công!');
      navigate('/'); // Chuyển hướng về trang chủ
    } catch (error) {
      alert(error.response?.data?.message || 'Sai email hoặc mật khẩu');
    }
  };

  return (
    <div className="d-flex justify-content-center align-items-center vh-100 bg-light">
      <div className="card p-4 shadow" style={{ width: '400px' }}>
        <h3 className="text-center text-primary mb-4">Đăng nhập HaiHand</h3>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label">Email</label>
            <input 
              type="email" 
              className="form-control" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required 
            />
          </div>
          <div className="mb-3">
            <label className="form-label">Mật khẩu</label>
            <input 
              type="password" 
              className="form-control" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required 
            />
          </div>
          <button type="submit" className="btn btn-primary w-100">Đăng Nhập</button>
        </form>
        <p className="mt-3 text-center">
          Chưa có tài khoản? <a href="/register">Đăng ký ngay</a>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
